```python
def unique_values(lst):
    return list(set(lst))

numbers = [1, 2, 2, 3, 3, 3, 4]
print(unique_values(numbers))  # [1, 2, 3, 4]

# To preserve original order:
def unique_ordered(lst):
    seen = set()
    result = []
    for x in lst:
        if x not in seen:
            seen.add(x)
            result.append(x)
    return result
```

