```python
def find_largest(numbers):
    if not numbers:
        return None
    largest = numbers[0]
    for n in numbers:
        if n > largest:
            largest = n
    return largest

prices = [450, 230, 890, 120, 670]
print(find_largest(prices))  # 890
# Or simply: max(prices)
```

